import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"市场行情","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/market-overview.md","filePath":"zh-CN/market-data/market-overview.md"}'),h={name:"market-data/market-overview.md"};function l(i,t,o,n,s,b){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="市场行情" tabindex="-1">市场行情 <a class="header-anchor" href="#市场行情" aria-label="Permalink to &quot;市场行情&quot;">​</a></h1><p>市场行情页展示各地区股票市场的指数走势、涨跌分布和热门股票排行，支持港股、美股、沪深、沪深港通和新加坡五个板块。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>底部导航「市场」→ 顶部切换「市场」标签 → 左右滑动切换板块。</p><h2 id="各板块说明" tabindex="-1">各板块说明 <a class="header-anchor" href="#各板块说明" aria-label="Permalink to &quot;各板块说明&quot;">​</a></h2><h3 id="港股" tabindex="-1">港股 <a class="header-anchor" href="#港股" aria-label="Permalink to &quot;港股&quot;">​</a></h3><p>展示港股市场的主要指数（如恒生指数、国企指数），以及市场整体涨跌分布和热门排行。</p><h3 id="美股" tabindex="-1">美股 <a class="header-anchor" href="#美股" aria-label="Permalink to &quot;美股&quot;">​</a></h3><p>展示美股三大指数（道琼斯、纳斯达克、标普 500），并提供市场温度仪表盘。</p><h3 id="沪深" tabindex="-1">沪深 <a class="header-anchor" href="#沪深" aria-label="Permalink to &quot;沪深&quot;">​</a></h3><p>展示 A 股三大指数（上证指数、深证成指、创业板指），并提供市场温度仪表盘。</p><h3 id="沪深港通" tabindex="-1">沪深港通 <a class="header-anchor" href="#沪深港通" aria-label="Permalink to &quot;沪深港通&quot;">​</a></h3><p>专门展示南北向资金流向数据，包含港股通（沪）和港股通（深）两个方向的资金明细。</p><h3 id="新加坡" tabindex="-1">新加坡 <a class="header-anchor" href="#新加坡" aria-label="Permalink to &quot;新加坡&quot;">​</a></h3><p>展示新加坡市场主要指数（富时海峡指数、富时海峡 REITs、富时海峡中国）及市场数据。</p><h2 id="通用功能模块" tabindex="-1">通用功能模块 <a class="header-anchor" href="#通用功能模块" aria-label="Permalink to &quot;通用功能模块&quot;">​</a></h2><p>各板块页面包含以下通用模块：</p><h3 id="指数概览卡片" tabindex="-1">指数概览卡片 <a class="header-anchor" href="#指数概览卡片" aria-label="Permalink to &quot;指数概览卡片&quot;">​</a></h3><p>以卡片形式展示该板块主要指数，每张卡片包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>指数名称</td><td>该市场的代表性指数</td></tr><tr><td>最新点位</td><td>实时更新的指数点位</td></tr><tr><td>涨跌幅</td><td>当日涨跌百分比</td></tr><tr><td>日内走势图</td><td>当日分时走势缩略图</td></tr></tbody></table><p>点击卡片进入该指数详情页。</p><h3 id="市场温度" tabindex="-1">市场温度 <a class="header-anchor" href="#市场温度" aria-label="Permalink to &quot;市场温度&quot;">​</a></h3><p>美股、沪深、新加坡板块提供市场温度仪表盘，从估值和情绪两个维度综合评估当前市场状态：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>温度值</td><td>0°~100° 之间，数值越高代表市场越热</td></tr><tr><td>估值判断</td><td>当前市场整体估值水平（偏低 / 正常 / 偏高 / 极高）</td></tr><tr><td>情绪判断</td><td>当前市场情绪状态（冰冻 / 平稳 / 高涨等）</td></tr><tr><td>状态描述</td><td>综合描述当前温度趋势</td></tr></tbody></table><p>点击市场温度卡片可查看详细分析报告。</p><h3 id="涨跌分布" tabindex="-1">涨跌分布 <a class="header-anchor" href="#涨跌分布" aria-label="Permalink to &quot;涨跌分布&quot;">​</a></h3><p>以横向柱状图展示当日全市场股票的涨跌家数分布，分为：</p><ul><li><strong>上涨</strong>：当日上涨的股票数量</li><li><strong>平盘</strong>：当日持平的股票数量</li><li><strong>下跌</strong>：当日下跌的股票数量</li></ul><h3 id="市场异动" tabindex="-1">市场异动 <a class="header-anchor" href="#市场异动" aria-label="Permalink to &quot;市场异动&quot;">​</a></h3><p>实时推送当日出现异常波动的股票：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>股票名称 / 代码</td><td>异动股票的名称和交易代码</td></tr><tr><td>异动类型</td><td>如急速拉升、加速下跌等</td></tr><tr><td>涨跌幅</td><td>当前涨跌百分比</td></tr><tr><td>时间</td><td>异动发生时间</td></tr></tbody></table><p>支持切换「市场异动」和「自选」标签，后者只显示用户自选股中的异动。</p><h3 id="热门股票排行" tabindex="-1">热门股票排行 <a class="header-anchor" href="#热门股票排行" aria-label="Permalink to &quot;热门股票排行&quot;">​</a></h3><p>展示当前市场热度最高的股票排名，支持按时间维度筛选：</p><ul><li>日内 / 5 分钟 / 半年 / 今年以来 / 创 52 周新高</li></ul><h2 id="沪深港通资金流向" tabindex="-1">沪深港通资金流向 <a class="header-anchor" href="#沪深港通资金流向" aria-label="Permalink to &quot;沪深港通资金流向&quot;">​</a></h2><p>沪深港通板块专项展示南北向资金数据：</p><h3 id="南向资金-港股通" tabindex="-1">南向资金（港股通） <a class="header-anchor" href="#南向资金-港股通" aria-label="Permalink to &quot;南向资金（港股通）&quot;">​</a></h3><p>内地资金流入香港市场的数据：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>成交净买入</td><td>当日净买入金额（正值为净买入，负值为净卖出）</td></tr><tr><td>实时净流向</td><td>实时更新的资金净流向</td></tr><tr><td>剩余额度</td><td>当日可用额度剩余情况</td></tr></tbody></table><p>分港股通（沪）和港股通（深）分别展示明细。</p><h3 id="北向资金-沪深股通" tabindex="-1">北向资金（沪深股通） <a class="header-anchor" href="#北向资金-沪深股通" aria-label="Permalink to &quot;北向资金（沪深股通）&quot;">​</a></h3><p>境外资金流入 A 股市场的数据，字段结构与南向资金相同。</p><h3 id="历史走势图" tabindex="-1">历史走势图 <a class="header-anchor" href="#历史走势图" aria-label="Permalink to &quot;历史走势图&quot;">​</a></h3><p>以柱状图展示近期每日成交净买入数据，直观呈现资金流向趋势。</p><h2 id="可执行操作" tabindex="-1">可执行操作 <a class="header-anchor" href="#可执行操作" aria-label="Permalink to &quot;可执行操作&quot;">​</a></h2><ul><li>点击指数卡片 → 进入指数详情页</li><li>点击市场温度 → 查看估值与情绪详细分析</li><li>切换异动 / 排行时间标签 → 过滤显示范围</li><li>点击个股 → 进入该股票行情详情页</li><li>点击右上角「关注」→ 快速添加自选股</li></ul>',47)])])}const u=a(h,[["render",l]]);export{c as __pageData,u as default};
